dashboard.definition:
{
  "visualizations": {
    "viz_table_output": {
      "type": "splunk.table",
      "dataSources": {
        "primary": "ds_ai_generator"
      },
      "options": {
        "columnFormat": {
          "gemini_analysis": {
            "width": 1000
          }
        }
      }
    },
    "viz_header_bg": {
      "type": "splunk.rectangle",
      "options": {
        "fillColor": "#1A252F",
        "strokeColor": "#3498DB",
        "strokeWidth": 3
      }
    },
    "viz_header_text": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# 💡 Splunk Dashboard Studio Generator (AI-Powered)\n**Transformasikan ide Anda menjadi Dashboard Studio yang modern dan interaktif secara instan.**\n\n1. Ketik kebutuhan SOC/Keamanan Anda di bawah ini.\n2. Tekan Enter.\n3. Copy kode JSON yang dihasilkan AI pada tabel di bawah, lalu paste di menu *Source* saat Anda membuat Dashboard Studio baru di Splunk.",
        "backgroundColor": "transparent"
      }
    },
    "viz_tips": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "**Tips Prompt:** *\"Buatkan saya Executive Dashboard untuk Ransomware dengan tema dark. Gunakan 3 single value di atas, 1 chart distribusi di tengah, dan layout absolute yang elegan.\"*",
        "backgroundColor": "transparent"
      }
    }
  },
  "dataSources": {
    "ds_ai_generator": {
      "type": "ds.search",
      "options": {
        "query": "| makeresults | eval _raw=\"\" | geminianalyze prompt=$prompt|s$ role=\"splunk_dashboard_studio_dev\" | table gemini_analysis",
        "queryParameters": {
          "earliest": "-1m",
          "latest": "now"
        }
      }
    }
  },
  "inputs": {
    "input_prompt": {
      "type": "input.text",
      "options": {
        "defaultValue": "Rancang dashboard SOC Executive Summary dengan layout absolute. Tambahkan 2 grafik pie untuk top IP dan top Malware, serta 1 tabel anomali.",
        "token": "prompt"
      },
      "title": "📝 Deskripsikan Detail Dashboard Anda (Lalu tekan Enter)"
    }
  },
  "layout": {
    "type": "absolute",
    "options": {
      "display": "auto",
      "backgroundColor": "#0B161E"
    },
    "structure": [
      {
        "item": "viz_header_bg",
        "type": "block",
        "position": {
          "x": 20,
          "y": 20,
          "w": 1160,
          "h": 140
        }
      },
      {
        "item": "viz_header_text",
        "type": "block",
        "position": {
          "x": 40,
          "y": 30,
          "w": 1120,
          "h": 120
        }
      },
      {
        "item": "viz_tips",
        "type": "block",
        "position": {
          "x": 20,
          "y": 170,
          "w": 1160,
          "h": 40
        }
      },
      {
        "item": "input_prompt",
        "type": "input",
        "position": {
          "x": 20,
          "y": 220,
          "w": 1160,
          "h": 60
        }
      },
      {
        "item": "viz_table_output",
        "type": "block",
        "position": {
          "x": 20,
          "y": 300,
          "w": 1160,
          "h": 600
        }
      }
    ]
  }
}
